INSERT INTO public.questions_answered (id, session_id, question_id, option_chosen_id, numeric_answer, selected_option_ids, answered_at, created_at, updated_at) VALUES ('28c7de5e-9d43-41e8-8319-76ba469daeaa', '28b24b0c-9c32-4aae-a249-0154fbcf9a2f', '13eacc8b-cfad-4f28-b10d-ed0e7526af5c', '997c3cb6-8231-4851-90f6-9ca101700a27', NULL, NULL, '2026-04-27 20:57:45.25383+00', '2026-04-27 20:57:45.25383+00', '2026-04-27 20:57:45.25383+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('515b8f2c-fef6-4be3-a644-ff2c1a3c1491', '0fba976c-dfa8-4dfd-9eb4-fe3e0d619d0e', 'The Label Detective', 'You''ve memorized the difference between maltodextrin and dextrose, and honestly? Respect. You eat with intention, research with enthusiasm, and probably have a strong opinion about oat milk. Your grocery cart is a masterpiece of deliberate choices.', 'See how Olive can sharpen your detective skills 🔍', 'https://oliveapp.com/#features', 28, 45, '2026-04-27 20:57:18.553816+00', '2026-04-27 20:57:18.553816+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('abbca85f-4714-4c03-8f84-06009b9a35c4', '0fba976c-dfa8-4dfd-9eb4-fe3e0d619d0e', 'The Conscious Balancer', 'You know enough to care, but you also know life is too short to skip dessert. You make thoughtful choices most of the time and extend yourself grace the rest of the time. Nutritionally self-aware, spiritually at peace.', 'Explore how Olive keeps your balance in check ⚖️', 'https://oliveapp.com/#features', 18, 27, '2026-04-27 20:57:18.553816+00', '2026-04-27 20:57:18.553816+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('0dca912a-eb65-4afb-8930-5edf20d9294c', '0fba976c-dfa8-4dfd-9eb4-fe3e0d619d0e', 'The Cheerful Pragmatist', 'You eat what works, you enjoy what tastes good, and you''re not losing sleep over it. You''ve got bigger things to think about than grams of fiber. Life is good and so is that Tuesday takeout.', 'Let Olive do the thinking so you don''t have to 🍕', 'https://oliveapp.com/', 9, 17, '2026-04-27 20:57:18.553816+00', '2026-04-27 20:57:18.553816+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('825214c7-f14d-463c-afef-ad6977b23c48', '0fba976c-dfa8-4dfd-9eb4-fe3e0d619d0e', 'The Blissfully Unaware', 'Food is fuel, fun, and frankly none of anyone''s business. You eat with pure instinct and zero spreadsheets, and there''s something genuinely freeing about that. Ignorance isn''t always bliss — but sometimes it totally is.', 'Discover what Olive might (gently) reveal 😇', 'https://oliveapp.com/', 0, 8, '2026-04-27 20:57:18.553816+00', '2026-04-27 20:57:18.553816+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('4b6daa02-e766-4d38-bc66-aeba2a6ade10', '60a4bd8f-9581-427d-a114-c8b716aa51e7', 'You''re a Whole Foods Hero 🥦', 'Your diet is impressively low in ultra-processed foods. You cook, you read labels, and you''re making choices your gut bacteria are genuinely excited about. Olive can help you keep that streak going and discover even more clean-ingredient wins.', 'Explore Olive', 'https://oliveapp.com/', 0, 15, '2026-04-27 20:56:10.288666+00', '2026-04-27 20:56:10.288666+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('a7c9500b-d0b3-4dc8-acea-8d0b9a91c968', '60a4bd8f-9581-427d-a114-c8b716aa51e7', 'Pretty Mindful, With Room to Grow 🌿', 'You''re making some solid choices, but a few ultra-processed habits are sneaking in. A little more label-reading and home cooking could make a big difference — and Olive is built to help you spot exactly where to level up.', 'See How Olive Can Help', 'https://oliveapp.com/#features', 16, 35, '2026-04-27 20:56:10.288666+00', '2026-04-27 20:56:10.288666+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('98b6cc3a-3c23-477e-94d0-dd272b153436', '60a4bd8f-9581-427d-a114-c8b716aa51e7', 'The Processed Food Middle Ground 🤔', 'You''re somewhere in the middle — not terrible, but ultra-processed foods are definitely a regular part of your routine. The good news: small swaps add up fast. Olive makes it easy to identify what''s worth changing.', 'Start Making Smarter Swaps', 'https://oliveapp.com/#features', 36, 55, '2026-04-27 20:56:10.288666+00', '2026-04-27 20:56:10.288666+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('e92b1db6-4792-4c64-9958-e1b298a4d5f8', '60a4bd8f-9581-427d-a114-c8b716aa51e7', 'Ultra-Processed Alert 🚨', 'Your diet is leaning heavily on ultra-processed foods, and your body is probably feeling it. The great news? You don''t have to overhaul everything overnight. Olive helps you make one better choice at a time — starting today.', 'Try Olive Today', 'https://oliveapp.com/', 56, 70, '2026-04-27 20:56:10.288666+00', '2026-04-27 20:56:10.288666+00');
